package com.google.gson.stream;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_withTrueBoolean_writesTrue() throws IOException {
    JsonWriter result = jsonWriter.value(true);
    assertSame(jsonWriter, result);
    assertEquals("true", stringWriter.toString());
  }

  @Test
  public void value_withFalseBoolean_writesFalse() throws IOException {
    JsonWriter result = jsonWriter.value(false);
    assertSame(jsonWriter, result);
    assertEquals("false", stringWriter.toString());
  }

  @Test
  public void value_withNullBoolean_callsNullValue() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    // Use spy to verify nullValue is called and value returns nullValue's result
    JsonWriter spyWriter = spy(jsonWriter);

    // Stub nullValue to return spyWriter for verification
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter result = spyWriter.value((Boolean) null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, result);
  }

  @Test
  public void writeDeferredName_and_beforeValue_areCalled_beforeWriting() throws Exception {
    JsonWriter spyWriter = spy(jsonWriter);

    // We need to set deferredName to non-null to trigger writeDeferredName writing something
    // Use reflection to set private deferredName field
    Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(spyWriter, "myName");

    // push a state on stack to avoid exceptions in writeDeferredName or beforeValue
    Field stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(spyWriter);
    stack[0] = 0; // EMPTY_DOCUMENT or similar
    Field stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(spyWriter, 1);

    // Instead of spying private methods directly (which is not possible),
    // use reflection to replace them with public wrappers or verify calls indirectly.
    // Here, we use reflection to intercept calls by overriding the methods via spy's doAnswer.

    // Create Method references
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // Use doAnswer to track calls to these private methods via reflection
    final boolean[] writeDeferredNameCalled = {false};
    final boolean[] beforeValueCalled = {false};

    doAnswer(invocation -> {
      writeDeferredNameCalled[0] = true;
      // call real private method via reflection
      writeDeferredNameMethod.invoke(spyWriter);
      return null;
    }).when(spyWriter).writeDeferredName();

    doAnswer(invocation -> {
      beforeValueCalled[0] = true;
      beforeValueMethod.invoke(spyWriter);
      return null;
    }).when(spyWriter).beforeValue();

    // Because writeDeferredName() and beforeValue() are private,
    // the above doAnswer won't work directly as spyWriter doesn't have public methods with these names.
    // So instead, we create a subclass that exposes these methods as public for testing.

    // Instead, invoke value(true) and then verify the order by checking the flags after reflection calls.

    // Clear flags
    writeDeferredNameCalled[0] = false;
    beforeValueCalled[0] = false;

    // To intercept the calls, we replace the spyWriter with a subclass that overrides these private methods as public

    class JsonWriterForTest extends JsonWriter {
      boolean writeDeferredNameCalled = false;
      boolean beforeValueCalled = false;

      JsonWriterForTest(StringWriter out) {
        super(out);
      }

      @Override
      public JsonWriter value(boolean value) throws IOException {
        try {
          if (value) {
            // Simulate the original method but call overridden private methods
            if (deferredName != null) {
              writeDeferredNamePublic();
            }
            beforeValuePublic();
            out.write("true");
            return this;
          } else {
            if (deferredName != null) {
              writeDeferredNamePublic();
            }
            beforeValuePublic();
            out.write("false");
            return this;
          }
        } catch (Exception e) {
          throw new IOException(e);
        }
      }

      public void writeDeferredNamePublic() throws Exception {
        writeDeferredNameCalled = true;
        Method m = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        m.setAccessible(true);
        m.invoke(this);
      }

      public void beforeValuePublic() throws Exception {
        beforeValueCalled = true;
        Method m = JsonWriter.class.getDeclaredMethod("beforeValue");
        m.setAccessible(true);
        m.invoke(this);
      }
    }

    JsonWriterForTest testWriter = new JsonWriterForTest(stringWriter);

    // Set deferredName and stack fields for testWriter via reflection
    deferredNameField.set(testWriter, "myName");
    stackField.set(testWriter, stack);
    stackSizeField.setInt(testWriter, 1);

    testWriter.value(true);

    assertTrue(testWriter.writeDeferredNameCalled, "writeDeferredName was not called");
    assertTrue(testWriter.beforeValueCalled, "beforeValue was not called");
  }

  @Test
  public void beforeValue_privateMethod_invocation() throws Exception {
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // push a state on stack to avoid exceptions
    Field stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 0; // EMPTY_DOCUMENT or similar
    Field stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);

    // Invoke private method beforeValue directly
    beforeValueMethod.invoke(jsonWriter);
  }

  @Test
  public void writeDeferredName_privateMethod_invocation() throws Exception {
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);

    // Set deferredName to non-null to test writing
    Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(jsonWriter, "name");

    // push a state on stack to avoid exceptions
    Field stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    int[] stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 0; // EMPTY_DOCUMENT or similar
    Field stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);

    writeDeferredNameMethod.invoke(jsonWriter);

    String output = stringWriter.toString();
    assertTrue(output.contains("name"));
  }
}
